{
  "summary": "This paper introduces AmbiBench, a benchmark designed to study task ambiguity in language models through six binary sentence classification tasks with ambiguous instructions. It demonstrates that large RLHF-trained models outperform humans and smaller models in disambiguation, and that finetuning on ambiguous examples can improve standard models' performance beyond RLHF models. The work highlights the importance of task ambiguity for robust model deployment and proposes a novel finetuning approach to address it.",
  "strengths": [
    {
      "point": "Novel benchmark addressing task ambiguity distinct from input ambiguity",
      "evidence": "AmbiBench consists of six ambiguously-specified binary classification tasks designed to isolate task ambiguity."
    },
    {
      "point": "Comprehensive empirical evaluation including humans, multiple model types, and finetuning",
      "evidence": "Experiments compare humans, RLHF-trained models, non-RLHF models, and smaller models under varying instruction clarity and example counts."
    },
    {
      "point": "Insightful finding that finetuning on ambiguous examples improves generalization",
      "evidence": "Finetuning on ambiguous in-context examples closes the gap with RLHF models and surpasses them on unseen tasks."
    }
  ],
  "weaknesses": [
    {
      "point": "Limited novelty due to insufficient comparison with prior ambiguity-related NLP work",
      "evidence": "The paper lacks thorough literature review and empirical comparison to prior work on polysemy, word sense disambiguation, or instruction ambiguity."
    },
    {
      "point": "Benchmark and task design overly simplified and restricted to binary linguistic feature pairs",
      "evidence": "AmbiBench focuses only on binary classification with pairs of linguistic features, limiting real-world applicability and ignoring more complex or multimodal ambiguities."
    },
    {
      "point": "Evaluation lacks strong baselines and detailed analysis",
      "evidence": "No inclusion of GPT-3.5, GPT-4, or open-source instruction-tuned models; metrics limited to accuracy; no detailed error or failure mode analysis."
    },
    {
      "point": "Reproducibility concerns due to missing details",
      "evidence": "Prompt templates, finetuning hyperparameters, human experiment details, and code/data availability are not fully specified."
    },
    {
      "point": "Clarity issues in defining ambiguity and structuring results",
      "evidence": "The paper conflates task, label, and input ambiguity and presents results without clear hierarchical structure or comprehensive summaries."
    }
  ],
  "questions": [
    {
      "question": "How does AmbiBench compare empirically to existing ambiguity-focused benchmarks or tasks in NLP?",
      "motivation": "Clarifying novelty and positioning AmbiBench relative to prior work is essential for assessing contribution."
    },
    {
      "question": "Can the findings generalize to multi-class, hierarchical, or multimodal task ambiguities beyond binary linguistic feature pairs?",
      "motivation": "Real-world tasks often involve more complex ambiguities, so understanding generalizability is critical for practical impact."
    },
    {
      "question": "Would inclusion of stronger instruction-tuned baselines like GPT-3.5 or GPT-4 change conclusions about the necessity of RLHF?",
      "motivation": "Determining whether RLHF or instruction tuning alone drives disambiguation performance affects methodological insights."
    },
    {
      "question": "What are the specific failure modes and error types when models fail under ambiguity?",
      "motivation": "Detailed error analysis could guide future improvements and better ambiguity resolution strategies."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
